INSERT INTO `os_video_project` (`id`, `user_id`, `title`, `source_url`, `source_platform`, `status`, `objective`, `summary`, `full_text`, `dialogue_text`, `narration_text`, `caption_text`, `created_at`, `updated_at`, `ai_analysis`, `media_url`, `remake_generation_status`, `remake_generation_provider`, `remake_generation_model`, `remake_generation_objective`, `remake_generation_asset_type`, `remake_generation_asset_name`, `remake_generation_asset_url`, `remake_generation_reference_frames`, `remake_generation_script`, `remake_generation_storyboard`, `remake_generation_prompt`, `remake_generation_task_id`, `remake_generation_result_url`, `remake_generation_error`, `remake_generation_updated_at`, `workflow_type`, `analysis_reference_frames`, `analysis_visual_features`, `remake_generation_audio_name`, `remake_generation_audio_url`) VALUES (1, 1, 'TikTok 钩子拆解示例1', 'https://www.tiktok.com/@demo/video/7490000000000000000', 'tiktok', 'ready', '提取完整口播、字幕并生成一版可复刻的短视频方案', '围绕 7490000000000000000 生成的第一版拆解结果，覆盖对话、旁白、字幕和复刻镜头建议。', '[narration] 旁白：先用一个强钩子开场，直接点出 提取完整口播、字幕并生成一版可复刻的短视频方案 的核心结果。\n[caption] 3 秒看懂 7490000000000000000 的内容抓手\n[dialogue] 主讲人：如果你也想复刻这个 TikTok 的节奏，先把镜头重点放在 提取完整口播、字幕并生成一版可复刻的短视频方案。\n[caption] Hook / Value / CTA\n[narration] 旁白：中段补充案例、数字或对比画面，让观众快速接受结论。\n[dialogue] 主讲人：最后给出一个明确行动建议，引导评论、私信或点击主页链接。', '如果你也想复刻这个 TikTok 的节奏，先把镜头重点放在 提取完整口播、字幕并生成一版可复刻的短视频方案。\n最后给出一个明确行动建议，引导评论、私信或点击主页链接。', '先用一个强钩子开场，直接点出 提取完整口播、字幕并生成一版可复刻的短视频方案 的核心结果。\n中段补充案例、数字或对比画面，让观众快速接受结论。', '3 秒看懂 7490000000000000000 的内容抓手\nHook / Value / CTA', '2026-03-27 04:00:25', '2026-03-28 16:10:17', NULL, NULL, 'idle', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'analysis', NULL, NULL, NULL, NULL);
INSERT INTO `os_video_project` (`id`, `user_id`, `title`, `source_url`, `source_platform`, `status`, `objective`, `summary`, `full_text`, `dialogue_text`, `narration_text`, `caption_text`, `created_at`, `updated_at`, `ai_analysis`, `media_url`, `remake_generation_status`, `remake_generation_provider`, `remake_generation_model`, `remake_generation_objective`, `remake_generation_asset_type`, `remake_generation_asset_name`, `remake_generation_asset_url`, `remake_generation_reference_frames`, `remake_generation_script`, `remake_generation_storyboard`, `remake_generation_prompt`, `remake_generation_task_id`, `remake_generation_result_url`, `remake_generation_error`, `remake_generation_updated_at`, `workflow_type`, `analysis_reference_frames`, `analysis_visual_features`, `remake_generation_audio_name`, `remake_generation_audio_url`) VALUES (3, 1, '分析脚本 · https://www.tiktok.com/@lucy52607/video/7618743685244570887', 'https://www.tiktok.com/@lucy52607/video/7618743685244570887', 'tiktok', 'ready', '从这个视频中提取完整的文本脚本，包括对话、旁白以及所有文字字幕：', '已基于真实视频解析完成 TikTok 来源 7618743685244570887 的拆解，通过 subtitles 提取了 2 段文本。 视频时长约 9.5 秒。', '[caption] 你说我是祥瑞\n[caption] 还是腰碎', '你说我是祥瑞\n还是腰碎', '', '你说我是祥瑞\n还是腰碎', '2026-03-29 14:18:01', '2026-03-29 15:51:19', 'AI 分析失败：Invalid response object from API: \'Your request was blocked.\' (HTTP response code was 403)', NULL, 'idle', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'analysis', NULL, NULL, NULL, NULL);
