INSERT INTO `os_video_project` (`id`, `user_id`, `title`, `source_url`, `source_platform`, `status`, `objective`, `summary`, `full_text`, `dialogue_text`, `narration_text`, `caption_text`, `created_at`, `updated_at`, `ai_analysis`, `media_url`, `remake_generation_status`, `remake_generation_provider`, `remake_generation_model`, `remake_generation_objective`, `remake_generation_asset_type`, `remake_generation_asset_name`, `remake_generation_asset_url`, `remake_generation_reference_frames`, `remake_generation_script`, `remake_generation_storyboard`, `remake_generation_prompt`, `remake_generation_task_id`, `remake_generation_result_url`, `remake_generation_error`, `remake_generation_updated_at`, `workflow_type`, `analysis_reference_frames`, `analysis_visual_features`, `remake_generation_audio_name`, `remake_generation_audio_url`) VALUES (10, 1, '复刻爆款 · https://www.tiktok.com/@electrictricycle.ameda/video/7611018671263108353', 'https://www.tiktok.com/@electrictricycle.ameda/video/7611018671263108353', 'tiktok', 'ready', '复刻这个视频的画面细节，包括画面构图、色彩、光影等：', '视频复刻已生成完成。', '[caption] Aimeda electric vehicles are hot sellers in Mexico,\n[caption] Brazil, Africa,\n[caption] Russia and Turkey. Precisely optimized for local conditions,\n[caption] they maintain stable performance in cold winters,\n[caption] rough roads and high temperatures.\n[caption] With strong power and reliable after sales service\n[caption] suitable for both daily commuting and cargo transportation,\n[caption] they are the ideal choice for overseas travel.', 'Aimeda electric vehicles are hot sellers in Mexico,\nBrazil, Africa,\nRussia and Turkey. Precisely optimized for local conditions,\nthey maintain stable performance in cold winters,\nrough roads and high temperatures.\nWith strong power and reliable after sales service\nsuitable for both daily commuting and cargo transportation,\nthey are the ideal choice for overseas travel.', '', 'Aimeda electric vehicles are hot sellers in Mexico,\nBrazil, Africa,\nRussia and Turkey. Precisely optimized for local conditions,\nthey maintain stable performance in cold winters,\nrough roads and high temperatures.\nWith strong power and reliable after sales service\nsuitable for both daily commuting and cargo transportation,\nthey are the ideal choice for overseas travel.', '2026-03-30 13:05:05', '2026-03-30 13:57:18', '{\n  \"visual\": {\n    \"aspect_ratio\": \"9:16\",\n    \"resolution\": \"720x1280\",\n    \"frame_rate\": \"30.00fps\",\n    \"composition\": {\n      \"subject_position\": \"主体更集中在画面中心，偏中近景或产品特写\",\n      \"subtitle_safe_area\": \"顶部预留约 12% 字幕安全区，左右各预留 5% 画面边距。\",\n      \"product_focus\": \"商品或核心动作必须占据画面宽度的 35%-55%，避免被字幕遮挡。\"\n    },\n    \"background\": {\n      \"layout\": \"背景主元素控制在 1-2 个，优先使用桌面、货架或居家功能位场景。\",\n      \"depth\": \"主体与背景建议拉开 0.8-1.5 米，避免画面扁平。\",\n      \"brand_elements\": \"背景可放 1 个与 7611018671263108353 同类的使用场景元素，避免杂物堆叠。\"\n    },\n    \"lighting\": {\n      \"key_light\": \"原片更接近 低照度氛围光，复刻时主光从人物或产品前方 45° 打入。\",\n      \"fill_light_ratio\": \"保持 高对比 的层次关系，补光控制在主光的 35%-45%。\",\n      \"back_light\": \"背光或轮廓光控制在主光的 15%-20%，只负责拉开主体边缘。\"\n    },\n    \"color\": {\n      \"palette\": \"主色参考 #606060 / #202020，色温整体中性。\",\n      \"contrast\": \"复刻时保持 高对比，主体与背景亮度差至少拉开 20%。\",\n      \"saturation\": \"整体建议维持 低饱和，不要为了吸睛牺牲产品细节。\"\n    },\n    \"camera_motion\": {\n      \"opening\": \"前 1.5 秒轻推镜 3%-5%，或者使用手持前移半步制造接近感。\",\n      \"body\": \"展示段整体参考 中节奏，切镜与稳镜交替，整体更偏常规短视频节奏。\",\n      \"turning_point\": \"转折段加入 1 次 cut-in 特写或前后对比画面，时长控制在 0.5-0.9 秒。\",\n      \"ending\": \"结尾保留 0.3-0.5 秒定镜，让 CTA 字幕完整停留。\"\n    },\n    \"replicable_parameters\": [\n      \"每 10 秒约 1.1 次明显场景切换\",\n      \"字幕字号建议占画面高度的 6%-8%，前 3 秒至少出现一次大字幕强化。\",\n      \"口播镜头优先用 24-35mm 等效焦段，避免广角拉扯脸型或产品形变。\",\n      \"输出视频保持 9:16，优先导出 720x1280，剪辑节奏按 30.00fps 处理。\",\n      \"素材整体为竖屏，节奏中节奏，画面低照度氛围光、高对比、低饱和，色温中性，主体更集中在画面中心，偏中近景或产品特写，建议复刻时延续这种镜头密度与光色关系。\"\n    ]\n  },\n  \"timeline\": [\n    {\n      \"stage\": \"Hook\",\n      \"start_s\": 0.0,\n      \