-- ----------------------------
-- Table structure for os_video_project_job
-- ----------------------------
DROP TABLE IF EXISTS `os_video_project_job`;
CREATE TABLE `os_video_project_job` (
  `id` int NOT NULL AUTO_INCREMENT,
  `project_id` int NOT NULL,
  `job_type` varchar(32) COLLATE utf8mb4_general_ci NOT NULL,
  `status` varchar(24) COLLATE utf8mb4_general_ci NOT NULL,
  `attempt` int NOT NULL,
  `max_attempts` int NOT NULL,
  `worker_id` varchar(120) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `lease_expires_at` datetime DEFAULT NULL,
  `started_at` datetime DEFAULT NULL,
  `finished_at` datetime DEFAULT NULL,
  `error_detail` text COLLATE utf8mb4_general_ci,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_os_video_project_job_status` (`status`),
  KEY `ix_os_video_project_job_worker_id` (`worker_id`),
  KEY `ix_os_video_project_job_project_id` (`project_id`),
  CONSTRAINT `os_video_project_job_ibfk_1` FOREIGN KEY (`project_id`) REFERENCES `os_video_project` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of os_video_project_job
-- ----------------------------
