-- ----------------------------
-- Table structure for os_video_project_task_step
-- ----------------------------
DROP TABLE IF EXISTS `os_video_project_task_step`;
CREATE TABLE `os_video_project_task_step` (
  `id` int NOT NULL AUTO_INCREMENT,
  `project_id` int NOT NULL,
  `step_key` varchar(64) COLLATE utf8mb4_general_ci NOT NULL,
  `title` varchar(80) COLLATE utf8mb4_general_ci NOT NULL,
  `detail` varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  `status` varchar(24) COLLATE utf8mb4_general_ci NOT NULL,
  `error_detail` text COLLATE utf8mb4_general_ci,
  `display_order` int NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_os_video_project_task_step_project_id` (`project_id`),
  CONSTRAINT `os_video_project_task_step_ibfk_1` FOREIGN KEY (`project_id`) REFERENCES `os_video_project` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=89 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

