-- ----------------------------
-- Table structure for os_video_remake_scene
-- ----------------------------
DROP TABLE IF EXISTS `os_video_remake_scene`;
CREATE TABLE `os_video_remake_scene` (
  `id` int NOT NULL AUTO_INCREMENT,
  `project_id` int NOT NULL,
  `scene_index` int NOT NULL,
  `visual_direction` text COLLATE utf8mb4_general_ci NOT NULL,
  `shot_prompt` text COLLATE utf8mb4_general_ci NOT NULL,
  `voiceover` text COLLATE utf8mb4_general_ci NOT NULL,
  `on_screen_text` text COLLATE utf8mb4_general_ci NOT NULL,
  `editing_notes` text COLLATE utf8mb4_general_ci NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_os_video_remake_scene_project_id` (`project_id`),
  CONSTRAINT `os_video_remake_scene_ibfk_1` FOREIGN KEY (`project_id`) REFERENCES `os_video_project` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=35 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of os_video_remake_scene
-- ----------------------------
BEGIN;
INSERT INTO `os_video_remake_scene` (`id`, `project_id`, `scene_index`, `visual_direction`, `shot_prompt`, `voiceover`, `on_screen_text`, `editing_notes`) VALUES (1, 1, 1, '近景人像 + 强对比背景，第一秒就把人和标题都顶出来。', '竖屏 9:16，创作者正对镜头，快速切入主题 提取完整口播、字幕并生成一版可复刻的短视频方案。', '先说结果，不铺垫。', 'TikTok 钩子拆解示例 核心钩子', '前 1.5 秒必须有大字幕和轻微推镜。');
INSERT INTO `os_video_remake_scene` (`id`, `project_id`, `scene_index`, `visual_direction`, `shot_prompt`, `voiceover`, `on_screen_text`, `editing_notes`) VALUES (2, 1, 2, '切入原视频同类场景的替代素材，保持快节奏。', '插入 2 到 3 个 B-roll，展示痛点、结果或前后对比。', '解释为什么这条内容能抓住停留。', '观众停留点', '每镜头 0.8 到 1.2 秒，配合节拍切换。');
INSERT INTO `os_video_remake_scene` (`id`, `project_id`, `scene_index`, `visual_direction`, `shot_prompt`, `voiceover`, `on_screen_text`, `editing_notes`) VALUES (3, 1, 3, '回到主讲人，加一个白板、手机界面或评论截图增强可信度。', '主讲人边说边指向画面中的关键要点。', '拆解脚本结构：钩子、价值、行动。', 'Hook / Value / CTA', '字幕逐词高亮，关键词加粗放大。');
INSERT INTO `os_video_remake_scene` (`id`, `project_id`, `scene_index`, `visual_direction`, `shot_prompt`, `voiceover`, `on_screen_text`, `editing_notes`) VALUES (4, 1, 4, '结尾拉近镜头，形成强 CTA。', '主讲人收束结论并给出一个下一步动作。', '如果你要复刻，先照这个节奏拍第一版。', '保存这套脚本模板', '结尾保留 0.5 秒静止画面，利于观众看清 CTA。');
INSERT INTO `os_video_remake_scene` (`id`, `project_id`, `scene_index`, `visual_direction`, `shot_prompt`, `voiceover`, `on_screen_text`, `editing_notes`) VALUES (9, 3, 1, '竖屏镜头，参考 0.3s - 1.9s 的原视频节奏。 当前任务目标：从这个视频中提取完整的文本脚本，包括对话、旁白以及所有文字字幕：。', '围绕这段真实内容复刻画面与镜头推进：你说我是祥瑞', '你说我是祥瑞', '你说我是祥瑞', '保持 TikTok 的剪辑速度，参考 30.00fps 与 1080x1920，整条视频时长约 9.5 秒。');
INSERT INTO `os_video_remake_scene` (`id`, `project_id`, `scene_index`, `visual_direction`, `shot_prompt`, `voiceover`, `on_screen_text`, `editing_notes`) VALUES (10, 3, 2, '竖屏镜头，参考 2.4s - 4.3s 的原视频节奏。 当前任务目标：从这个视频中提取完整的文本脚本，包括对话、旁白以及所有文字字幕：。', '围绕这段真实内容复刻画面与镜头推进：还是腰碎', '还是腰碎', '还是腰碎', '保持 TikTok 的剪辑速度，参考 30.00fps 与 1080x1920，整条视频时长约 9.5 秒。');
