-- ----------------------------
-- Table structure for os_video_transcript_segment
-- ----------------------------
DROP TABLE IF EXISTS `os_video_transcript_segment`;
CREATE TABLE `os_video_transcript_segment` (
  `id` int NOT NULL AUTO_INCREMENT,
  `project_id` int NOT NULL,
  `segment_type` varchar(32) COLLATE utf8mb4_general_ci NOT NULL,
  `speaker` varchar(80) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `start_ms` int NOT NULL,
  `end_ms` int NOT NULL,
  `content` text COLLATE utf8mb4_general_ci NOT NULL,
  `display_order` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_os_video_transcript_segment_project_id` (`project_id`),
  CONSTRAINT `os_video_transcript_segment_ibfk_1` FOREIGN KEY (`project_id`) REFERENCES `os_video_project` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=73 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

